def test_ach_transfer_insufficient_funds_returns_409(
    auth_headers, verified_ach_account, low_balance_account_headers
):
    payload = {
        "destination_account_id": verified_ach_account["id"],
        "amount": 500.00,
        "currency": "USD"
    }
    resp = <api_client>.post(
        "/transfers/ach", json=payload, headers=low_balance_account_headers
    )
    assert resp.status_code == 409
    body = resp.json()
    assert "INSUFFICIENT_FUNDS" in body.get("error_code", "").upper() or \
           "insufficient" in body.get("message", "").lower()

def test_ach_transfer_unverified_link_returns_403(
    auth_headers, unverified_ach_account
):
    payload = {
        "destination_account_id": unverified_ach_account["id"],
        "amount": 500.00,
        "currency": "USD"
    }
    resp = <api_client>.post("/transfers/ach", json=payload, headers=auth_headers)
    assert resp.status_code in (403, 422)
    body = resp.json()
    msg = (body.get("error_code", "") + body.get("message", "")).lower()
    assert any(kw in msg for kw in ("unauthori", "unverified", "not verified", "forbidden"))
